			if (!payload?.text && !payload?.mediaUrl && !payload?.mediaUrls?.length) continue;
			if (isSilentReplyText(payload.text, SILENT_REPLY_TOKEN) && !payload.mediaUrl && !payload.mediaUrls?.length) continue;
